/* SgiMgmtMapper.getSgiDmndList */ SELECT FN_GET_CODENM('CMN0218', DUTY_SCTN) AS DUTY_SCTN ,FN_GET_CODENM('CMN0224', CMPN_SCTN) AS CMPN_SCTN ,INSR_BILL_REQ_NO AS INSR_BILL_REQ_NO ,RESULT_CD AS RESULT_CD ,ERR_RESULT_CNTT AS ERR_RESULT_CNTT ,BLANKS AS BLANKS ,SECURITIES_NO AS SECURITIES_NO ,INSR_MNGM_NO AS INSR_MNGM_NO ,SVC_NO AS SVC_NO ,SVC_NO_BLANKS AS SVC_NO_BLANKS ,FN_GET_CODENM('CMN0219', CSTMR_CD) AS CSTMR_CD ,SUBSTR(USER_SSN, 1,6) AS USER_SSN ,CSTMR_NAME AS CSTMR_NAME ,INDV_ENTR_NO AS INDV_ENTR_NO ,PAYER_ID AS PAYER_ID ,LST_MODEL_NAME AS LST_MODEL_NAME ,LST_MODEL_SERIAL_NO AS LST_MODEL_SERIAL_NO ,SUBSCRIBER_NO AS SUBSCRIBER_NO ,OFFICIO_REVOCATION_DATE AS OFFICIO_REVOCATION_DATE ,FN_GET_CODENM('CMN0220', PART_PAY_REVOCATION_YN) AS PART_PAY_REVOCATION_YN ,NAME_CHANGE_DATE AS NAME_CHANGE_DATE ,PHONE_JOIN_DATE AS PHONE_JOIN_DATE ,INSR_STRT_DATE AS INSR_STRT_DATE ,INSR_TRMN_DATE AS INSR_TRMN_DATE ,INST_CNT AS INST_CNT ,INST_PAY_NUM AS INST_PAY_NUM ,INSR_JOIN_AMT AS INSR_JOIN_AMT ,BILL_DATE AS BILL_DATE ,BILL_AMT AS BILL_AMT ,INST_RATE AS INST_RATE ,FST_UNPAY_DATE AS FST_UNPAY_DATE ,FST_UNPAY_NUM AS FST_UNPAY_NUM ,RESIDENCE_SUBSCRIBER_NO AS RESIDENCE_SUBSCRIBER_NO ,RESIDENCE_POST AS RESIDENCE_POST ,BILL_ADDR_SUBSCRIBER_NO AS BILL_ADDR_SUBSCRIBER_NO ,BILL_ADDR_POST AS BILL_ADDR_POST ,FN_GET_CODENM('CMN0221', RESIDENCE_CD) AS RESIDENCE_CD ,RESIDENCE_ADDR||RESIDENCE_ADDR_DTL AS RESIDENCE_ADDR ,FN_GET_CODENM('CMN0222', BILL_ADDR_CD) AS BILL_ADDR_CD ,BILL_ADDR||BILL_ADDR_DTL AS BILL_ADDR ,BRANCH_CD AS BRANCH_CD ,MINOR_NAME AS MINOR_NAME ,MINOR_SSN AS MINOR_SSN ,INDV_REVIVAL_YN AS INDV_REVIVAL_YN ,FN_GET_CODENM('CMN0227',INDV_REVIVAL_STEP) AS INDV_REVIVAL_STEP ,INDV_REVIVAL_REPAY_YN AS INDV_REVIVAL_REPAY_YN ,INDV_REVIVAL_REPAY_AMT AS INDV_REVIVAL_REPAY_AMT ,BANKRUPTCY_EXEMPTION_YN AS BANKRUPTCY_EXEMPTION_YN FROM CMN_SGIH_DMND
WHERE FILE_NM LIKE '%'||#{baseDate}||'%'
ORDER BY CMN_SGIH_DMND_SEQ_NUM

